static PyObject *Dtool_Repr_Geom(PyObject *self) {
  Geom *local_this = nullptr;
  if (!Dtool_Call_ExtractThisPointer(self, Dtool_Geom, (void **)&local_this)) {
    return nullptr;
  }

  std::ostringstream os;
  local_this->output(os);
  std::string ss = os.str();
  return Dtool_WrapValue(ss);
}

//////////////////
//  A __str__ function
//     Geom
//////////////////
static PyObject *Dtool_Str_Geom(PyObject *self) {
  Geom *local_this = nullptr;
  if (!Dtool_Call_ExtractThisPointer(self, Dtool_Geom, (void **)&local_this)) {
    return nullptr;
  }

  std::ostringstream os;
  local_this->write(os);
  std::string ss = os.str();
  return Dtool_WrapValue(ss);
}

static int Dtool_Traverse_Geom(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  Geom *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_Geom, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

static int Dtool_Clear_Geom(PyObject *self) {
  if (Py_TYPE(self) != &Dtool_Geom._PyType && DtoolInstance_TYPE(self) == &Dtool_Geom) {
    DtoolProxy_Geom *proxy = (DtoolProxy_Geom *)DtoolInstance_VOID_PTR(self);
    Py_CLEAR(proxy->DtoolProxy::_self);
  }
  return 0;
}

