static PyObject *Dtool_Str_Texture(PyObject *self) {
  Texture *local_this = nullptr;
  if (!Dtool_Call_ExtractThisPointer(self, Dtool_Texture, (void **)&local_this)) {
    return nullptr;
  }

  std::ostringstream os;
  local_this->write(os, 0);
  std::string ss = os.str();
  return Dtool_WrapValue(ss);
}

static int Dtool_Traverse_Texture(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  Texture *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_Texture, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

static int Dtool_Clear_Texture(PyObject *self) {
  if (Py_TYPE(self) != &Dtool_Texture._PyType && DtoolInstance_TYPE(self) == &Dtool_Texture) {
    DtoolProxy_Texture *proxy = (DtoolProxy_Texture *)DtoolInstance_VOID_PTR(self);
    Py_CLEAR(proxy->DtoolProxy::_self);
  }
  return 0;
}

