static int Dtool_Traverse_Shader(PyObject *self, visitproc visit, void *arg) {
  // If the only reference remaining is the one held by the Python wrapper,
  // report the circular reference to Python's GC, so that it can break it.
  Shader *local_this;
  DTOOL_Call_ExtractThisPointerForType(self, &Dtool_Shader, (void**)(&local_this));
  if (local_this == nullptr) {
    return 0;
  }
  if (local_this->get_ref_count() == (int)((Dtool_PyInstDef *)self)->_memory_rules) {
    Py_VISIT(self);
  }
  return 0;
}

static int Dtool_Clear_Shader(PyObject *self) {
  if (Py_TYPE(self) != &Dtool_Shader._PyType && DtoolInstance_TYPE(self) == &Dtool_Shader) {
    DtoolProxy_Shader *proxy = (DtoolProxy_Shader *)DtoolInstance_VOID_PTR(self);
    Py_CLEAR(proxy->DtoolProxy::_self);
  }
  return 0;
}

